var currentLang='fr';
function t(key){
  var lang=translations[currentLang];
  if(!lang)return key;
  var val=lang[key];
  if(typeof val==='function')return val;
  return val||key;
}
function setLanguage(lang){
  currentLang=lang;
  var html=document.documentElement;
  var body=document.body;
  if(lang==='ar'){
    html.setAttribute('lang','ar');
    html.setAttribute('dir','rtl');
    body.classList.add('rtl');
  }else{
    var langMap={fr:'fr',en:'en',es:'es'};
    html.setAttribute('lang',langMap[lang]||lang);
    html.setAttribute('dir','ltr');
    body.classList.remove('rtl');
  }
  document.querySelectorAll('[data-i18n]').forEach(function(el){
    var key=el.getAttribute('data-i18n');
    var val=t(key);
    if(typeof val==='string'){
      if(val.indexOf('<br>')>-1||val.indexOf('>')>-1){
        el.innerHTML=val;
      }else{
        el.textContent=val;
      }
    }
  });
  document.querySelectorAll('[data-i18n-placeholder]').forEach(function(el){
    var key=el.getAttribute('data-i18n-placeholder');
    var val=t(key);
    if(typeof val==='string'){
      el.placeholder=val;
    }
  });
  if(t('page.title'))document.title=t('page.title');
  if(t('page.description')){
    var meta=document.querySelector('meta[name="description"]');
    if(meta)meta.setAttribute('content',t('page.description'));
  }
  document.querySelectorAll('.lang-pill').forEach(function(p){
    p.classList.toggle('active',p.getAttribute('data-lang')===lang);
  });
  try{localStorage.setItem('wh-lang',lang)}catch(e){}
}
document.querySelectorAll('.lang-pill').forEach(function(pill){
  pill.addEventListener('click',function(){
    setLanguage(this.getAttribute('data-lang'));
  });
});
(function(){
  try{
    var saved=localStorage.getItem('wh-lang');
    if(saved&&translations[saved]){
      setLanguage(saved);
    }else{
      setLanguage('fr');
    }
  }catch(e){setLanguage('fr');}
})();
